// Single source of truth → SDK + executor (+ the SDK-carried JSON the app pins).
//
// Reads deployments/base-sepolia.json (which the deploy scripts write) and
// regenerates the per-client address files from it, so no address is ever
// hand-copied into a client again (the cause of the #147 / #151 staleness bugs).
// Run after EVERY redeploy, from the repo root:
//
//   node scripts/gen-addresses.mjs
//
// Then commit the generated files. Outputs:
//   - sdk/deployments/base-sepolia.json
//       The cross-language carrier. Shipped inside the @bytesbrains/maktub-sdk
//       npm package (package.json "files"). The Flutter app pins an SDK *version*
//       and regenerates its Dart constants from this file via its own codegen tool
//       — it no longer receives a cross-repo file write (#87). Before the split this
//       script also wrote mobile/lib/services/contract_addresses.g.dart directly into
//       the sibling app tree; that path is gone now that the app is its own repo.
//   - sdk/src/constants/sepolia_addresses.generated.ts   (TS ergonomics for the SDK)
//   - executor/src/addresses.generated.js                (the executor, CommonJS)
//
// A redeploy is: update deployments/base-sepolia.json → run this → bump the SDK
// version → publish → each downstream bumps its pinned dep. CI drift-guards that the
// generated files always match deployments/base-sepolia.json.

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
const json = JSON.parse(
  readFileSync(join(repoRoot, "deployments", "base-sepolia.json"), "utf8")
);

const c = json.contracts ?? {};
const deployedAt = json.deployedAt ?? "unknown";
const chainId = json.chainId ?? 84532;
const deployBlock = json.deployBlock ?? 0;
// MaktubFlash can be on an older stack than the Beat redeploy (it is not
// redeployed every freeze), so its event-log scan floor is tracked separately.
// Falls back to deployBlock when the deploy record doesn't carry it.
const flashDeployBlock = json.flashDeployBlock ?? deployBlock;

function addr(key) {
  const v = c[key];
  if (!v) throw new Error(`contracts.${key} missing in deployments/base-sepolia.json`);
  return v;
}

const A = {
  MaktubCore: addr("MaktubCore"),
  RecipientRegistry: addr("RecipientRegistry"),
  RecipientRegistryV2: addr("RecipientRegistryV2"),
  MaktubFlash: addr("MaktubFlash"),
  MktbToken: addr("MktbToken"),
  ExecutorRewards: addr("ExecutorRewards"),
  ExecutionRelay: addr("ExecutionRelay"),
  MktbGovernance: addr("MktbGovernance"),
};

const banner =
  `// GENERATED by scripts/gen-addresses.mjs — DO NOT EDIT.\n` +
  `// Single source of truth: deployments/base-sepolia.json (stack of ${deployedAt}).\n` +
  `// Regenerate after any redeploy: node scripts/gen-addresses.mjs\n`;

// ── 1. SDK carrier (JSON, cross-language) ──────────────────────────────────
// The canonical client view of the live deployment, shipped in the npm package.
// Downstream that cannot consume TypeScript (e.g. the Flutter app) reads THIS,
// pinned to an SDK version, instead of syncing deployments/base-sepolia.json.
const carrier = {
  _generated:
    "GENERATED by scripts/gen-addresses.mjs from deployments/base-sepolia.json — DO NOT EDIT.",
  chainId,
  deployedAt,
  deployBlock,
  // Flash is not redeployed every Beat freeze; its log scans use this floor.
  flashDeployBlock,
  contracts: {
    maktubCore: A.MaktubCore,
    recipientRegistry: A.RecipientRegistry,
    recipientRegistryV2: A.RecipientRegistryV2,
    maktubFlash: A.MaktubFlash,
    mktbToken: A.MktbToken,
    executorRewards: A.ExecutorRewards,
    executionRelay: A.ExecutionRelay,
    mktbGovernance: A.MktbGovernance,
  },
};
mkdirSync(join(repoRoot, "sdk/deployments"), { recursive: true });
writeFileSync(
  join(repoRoot, "sdk/deployments/base-sepolia.json"),
  JSON.stringify(carrier, null, 2) + "\n"
);

// ── 2. SDK (TypeScript) ────────────────────────────────────────────────────
const ts = `${banner}
export const SEPOLIA_CHAIN_ID = ${chainId};
export const SEPOLIA_DEPLOY_BLOCK = ${deployBlock};
// Flash is not redeployed every Beat freeze — its log scans use its own floor.
export const SEPOLIA_FLASH_DEPLOY_BLOCK = ${flashDeployBlock};

export const SEPOLIA_CONTRACTS = {
  maktubCore: "${A.MaktubCore}",
  recipientRegistry: "${A.RecipientRegistry}",
  mktbToken: "${A.MktbToken}",
  executorRewards: "${A.ExecutorRewards}",
  mktbGovernance: "${A.MktbGovernance}",
  executionRelay: "${A.ExecutionRelay}",
  recipientRegistryV2: "${A.RecipientRegistryV2}",
  maktubFlash: "${A.MaktubFlash}",
};
`;
writeFileSync(join(repoRoot, "sdk/src/constants/sepolia_addresses.generated.ts"), ts);

// ── 3. Executor (CommonJS) ─────────────────────────────────────────────────
const js = `${banner}
module.exports = {
  deployBlock: ${deployBlock},
  contracts: {
    MktbToken: "${A.MktbToken}",
    ExecutorRewards: "${A.ExecutorRewards}",
    MaktubCore: "${A.MaktubCore}",
    RecipientRegistry: "${A.RecipientRegistry}",
    ExecutionRelay: "${A.ExecutionRelay}",
  },
};
`;
writeFileSync(join(repoRoot, "executor/src/addresses.generated.js"), js);

console.log(`Generated SDK carrier + SDK TS + executor addresses (stack ${deployedAt}).`);
